-- migrations/065_sfaf_field_registry.sql
-- Categories, field definitions, and required field config for full SFAF Codes manager

-- =========================================================
-- sfaf_field_categories
-- =========================================================
CREATE TABLE IF NOT EXISTS sfaf_field_categories (
    id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    name        VARCHAR(100) NOT NULL,
    sort_order  INT NOT NULL DEFAULT 0,
    created_at  TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP
);


-- =========================================================
-- sfaf_field_definitions
-- =========================================================
CREATE TABLE IF NOT EXISTS sfaf_field_definitions (
    id                      UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    field_number            VARCHAR(10) NOT NULL UNIQUE,
    title                   VARCHAR(200) NOT NULL,
    category_id             UUID REFERENCES sfaf_field_categories(id) ON DELETE SET NULL,
    spectrum_xxi_tags       VARCHAR(100),
    gmf_tags                VARCHAR(200),
    max_input_length        VARCHAR(50),
    max_occurrences         VARCHAR(20),
    to_irac                 VARCHAR(10),
    max_chars_per_occurrence INT,
    max_chars_per_line      INT,
    has_lookup              BOOLEAN NOT NULL DEFAULT false,
    sort_order              INT NOT NULL DEFAULT 0,
    notes                   TEXT,
    is_active               BOOLEAN NOT NULL DEFAULT true,
    created_at              TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at              TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP
);


-- =========================================================
-- sfaf_required_fields
-- =========================================================
CREATE TABLE IF NOT EXISTS sfaf_required_fields (
    id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    field_number VARCHAR(10) NOT NULL,
    scope_type  VARCHAR(20) NOT NULL CHECK (scope_type IN ('global','agency','unified_command','majcom')),
    scope_value VARCHAR(100) NOT NULL DEFAULT '',
    created_by  UUID,
    created_at  TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE UNIQUE INDEX IF NOT EXISTS uix_sfaf_required_fields
    ON sfaf_required_fields(field_number, scope_type, scope_value);
